import { Router } from "express";
import { authController } from "../../modules/auth/auth.controller.js";
import { authRequired } from "../../middlewares/authRequired.js";
export const authRoutes = Router();
authRoutes.post("/login", (req, res, next) => void authController.login(req, res).catch(next));
authRoutes.post("/refresh", (req, res, next) => void authController.refresh(req, res).catch(next));
authRoutes.post("/logout", (req, res, next) => void authController.logout(req, res).catch(next));
authRoutes.get("/me", authRequired, (req, res, next) => void authController.me(req, res).catch(next));
authRoutes.post("/forgot-password", (req, res, next) => void authController.forgotPassword(req, res).catch(next));
authRoutes.post("/reset-password", (req, res, next) => void authController.resetPassword(req, res).catch(next));
